/**
 * uapi.ts — UAPI (uapis.cn) 第三方 B站 API 客户端
 * 使用官方 SDK `uapi-sdk-typescript`，免费额度，无需 Token
 */

import pRetry from "p-retry";
import { UapiClient } from "uapi-sdk-typescript";
import type { VideoEntry } from "./types.ts";
import { sleep } from "./utils.ts";

// B站 UID（mid）
export const UID = "3706929260006322";

const PAGE_SIZE = 50;
const client = new UapiClient("https://uapis.cn");

/** 获取单页 */
function fetchPage(page: number) {
  return client.social.getSocialBilibiliArchives({
    mid: UID,
    ps: String(PAGE_SIZE),
    pn: String(page),
    orderby: "pubdate",
    disableCache: page > 1,
  });
}

/** 将 UAPI 视频条目映射为 VideoEntry */
function mapToVideoEntry(v: {
  aid?: number;
  bvid?: string;
  title?: string;
  publish_time?: number;
}): VideoEntry {
  const created = v.publish_time ?? 0;
  return {
    bvid: v.bvid ?? "",
    aid: v.aid ?? 0,
    title: v.title ?? "",
    created,
    createdDate: created
      ? new Date(created * 1000).toISOString().split("T")[0]
      : "",
  };
}

/** 通过 UAPI 分页获取所有视频 */
export async function fetchAllVideosFromUapi(): Promise<VideoEntry[]> {
  console.log(`🚀 开始通过 UAPI 获取博主 ${UID} 的视频列表...\n`);

  const firstPage = await pRetry(() => fetchPage(1), {
    retries: 3,
    minTimeout: 1000,
    factor: 2,
    maxTimeout: 8000,
    onFailedAttempt: (err) =>
      console.error(
        `  ⚠️ UAPI 第一页请求 失败 (${err.attemptNumber}/${err.retriesLeft + err.attemptNumber})，${Math.min(err.attemptNumber * 1000, 8000) / 1000}s 后重试...`,
      ),
  });

console.log(`🚀 开始通过 UAPI 获取博主 ${UID} 的视频列表...\n`);

  const firstPage = await pRetry(() => fetchPage(1), {
    retries: 3,
    minTimeout: 1000,
    factor: 2,
    maxTimeout: 8000,
    onFailedAttempt: (err) =>
      console.error(
        `  ⚠️ UAPI 第一页请求 失败 (${err.attemptNumber}/${err.retriesLeft + err.attemptNumber})，${Math.min(err.attemptNumber * 1000, 8000) / 1000}s 后重试...`,
      ),
  });

  const totalCount = firstPage.total ?? 0;
  console.log(`📊 共 ${totalCount} 个视频`);

  const allVideos: VideoEntry[] = (firstPage.videos ?? []).map(mapToVideoEntry);
  console.log(`  ✅ 第 1 页: ${firstPage.videos?.length ?? 0} 个视频`);

  let page = 2;
  while (allVideos.length < totalCount) {
    await sleep(1500);

    try {
      const pageData = await fetchPage(page);
      const videos = pageData.videos ?? [];
      if (videos.length === 0) break; // UAPI total 可能大于实际可返回数
      allVideos.push(...videos.map(mapToVideoEntry));
      console.log(`  ✅ 第 ${page} 页: ${videos.length} 个视频`);
    } catch (err) {
      console.error(
        `  ❌ 第 ${page} 页失败: ${(err as Error)?.message ?? String(err)}`,
      );
      await sleep(3000);
    }

    page++;
  }

  console.log(`\n📹 已收集 ${allVideos.length} 个视频标题 (via UAPI)\n`);
  return allVideos;
}

/** 限速等待（毫秒） */
export const sleep = (ms: number): Promise<void> =>
  new Promise((r) => setTimeout(r, ms));

import type { AnalysisData } from "../types.ts";

/** 生成「核心特征」段落 */
export function genCoreFeatures(data: AnalysisData): string {
  const { length, punctuation, aiDaily, patterns, keywords } = data;
  const lines: string[] = [];
  lines.push("### 核心特征");
  lines.push("");
  lines.push(
    `1. **超长标题**：平均 ${length.avg} 字，${length.over40Pct}% 超过 40 字`,
  );
  lines.push(
    `2. **情绪炸弹**：大量使用感叹号（${Math.round(punctuation.exclamationEnd * 100)}%）和情绪词`,
  );
  lines.push("3. **多事件合并**：一个标题常包含 2-3 条新闻");

  const dominant = Object.entries(patterns.structure)
    .filter(([cat]) => cat !== "其他")
    .sort((a, b) => b[1].count - a[1].count)[0];
  if (dominant) {
    lines.push(
      `4. **AI 日报格式**：${aiDaily.pct}% 的标题带 "| AI日报MMDD" 后缀`,
    );
    lines.push(
      `5. **主导风格**：「${dominant[0]}」占比 ${dominant[1].pctDisplay}`,
    );
  }
  lines.push(
    `6. **独特词汇**：${keywords.uniqueExpressions.slice(0, 10).join("、")}`,
  );
  lines.push("");

  return lines.join("\n");
}

import type { AnalysisData } from "../types.ts";

/** 生成「结构公式」段落 */
export function genStructureFormulas(data: AnalysisData): string {
  const structure = data.patterns.structure;
  const lines: string[] = [];

  // 公式1: 情感式
  if (
    structure["情感式"]?.templates?.length &&
    structure["情感式"].templates.length > 0
  ) {
    lines.push(
      `**公式1：情绪词 + 主题 + 副标题（最常用，${structure["情感式"].pctDisplay}）**`,
    );
    lines.push("```");
    lines.push("{情绪词}！{主题}，{副标题}！");
    lines.push("```");
    lines.push("");
  }

  // 公式2: 多事件合并
  lines.push("**公式2：多事件合并**");
  lines.push("```");
  lines.push("{事件1}！{事件2}！{事件3}！| AI日报{MMDD}");
  lines.push("```");
  lines.push("");

  // 公式3: 悬念式
  if (
    structure["悬念式"]?.templates?.length &&
    structure["悬念式"].templates.length > 0
  ) {
    lines.push(`**公式3：悬念式（${structure["悬念式"].pctDisplay}）**`);
    lines.push("```");
    lines.push("{情绪词}！{主题}泄露/曝出/传出，{副标题}？");
    lines.push("```");
    lines.push("");
  }

  // 公式4: 日报式
  lines.push(`**公式4：日报式（${data.aiDaily.pct}%）**`);
  lines.push("```");
  lines.push("{主题} | AI日报{MMDD}");
  lines.push("```");
  lines.push("");

  // 分类占比表
  lines.push("### 分类占比");
  lines.push("");
  lines.push("| 类型 | 数量 | 占比 |");
  lines.push("|------|------|------|");
  for (const [cat, info] of Object.entries(structure)) {
    lines.push(`| ${cat} | ${info.count} | ${info.pctDisplay} |`);
  }
  lines.push("");

  return lines.join("\n");
}

import type { AnalysisData } from "../types.ts";

/** 生成「真实标题示例」段落 */
export function genTitleExamples(data: AnalysisData): string {
  const structure = data.patterns.structure;
  const lines: string[] = [];
  lines.push("### 真实标题示例（直接学习）");
  lines.push("");

  // 情感式
  const qinggan = structure["情感式"];
  if (qinggan && qinggan.examples.length > 0) {
    lines.push(`**情感式（最常用，${qinggan.pctDisplay}）**：`);
    lines.push("```");
    for (const t of qinggan.examples.slice(0, 5)) lines.push(t);
    lines.push("```");
    lines.push("");
  }

  // 悬念式
  const xuannian = structure["悬念式"];
  if (xuannian && xuannian.examples.length > 0) {
    lines.push(`**悬念式（${xuannian.pctDisplay}）**：`);
    lines.push("```");
    for (const t of xuannian.examples.slice(0, 3)) lines.push(t);
    lines.push("```");
    lines.push("");
  }

  // 日报式
  const withDaily = (structure["其他"]?.examples || [])
